<?php
declare(strict_types=1);

function enhanced_site_page(int $id):array{$q=db()->prepare('SELECT p.*,s.slug site_slug,s.name site_name,s.tracking_enabled,s.consent_mode FROM site_pages p JOIN sites s ON s.id=p.site_id WHERE p.id=?');$q->execute([$id]);$r=$q->fetch();if(!$r){http_response_code(404);exit('Page not found');}return $r;}
function site_tracking_allowed(array $page):bool{$mode=(string)$page['consent_mode'];return $page['tracking_enabled']&&$mode!=='disabled'&&($mode!=='required'||($_COOKIE['oc_consent']??'')==='granted')&&($_COOKIE['oc_consent']??'')!=='denied';}
function site_uuid():string{$b=random_bytes(16);$b[6]=chr((ord($b[6])&15)|64);$b[8]=chr((ord($b[8])&63)|128);return vsprintf('%s%s-%s-%s-%s-%s%s%s',str_split(bin2hex($b),4));}

if($path==='/sites/assets'){
 require_permission('sites.view');
 if($method==='POST'){
  require_permission('sites.edit');verify_csrf();$file=$_FILES['file']??null;if(!$file||$file['error']!==UPLOAD_ERR_OK){http_response_code(422);exit('Upload failed.');}
  if((int)$file['size']>10*1024*1024){http_response_code(413);exit('Files are limited to 10 MB.');}
  $mime=(new finfo(FILEINFO_MIME_TYPE))->file($file['tmp_name']);$allowed=['image/jpeg'=>'jpg','image/png'=>'png','image/gif'=>'gif','image/webp'=>'webp','application/pdf'=>'pdf'];if(!isset($allowed[$mime])){http_response_code(415);exit('Use JPG, PNG, GIF, WebP, or PDF files.');}
  $stored=bin2hex(random_bytes(20)).'.'.$allowed[$mime];$dir=dirname(__DIR__).'/storage/uploads/site-assets';if(!is_dir($dir)&&!mkdir($dir,0770,true))throw new RuntimeException('Asset directory could not be created.');if(!move_uploaded_file($file['tmp_name'],$dir.'/'.$stored))throw new RuntimeException('Asset could not be stored.');
  $siteId=(int)post('site_id')?:null;db()->prepare('INSERT INTO site_assets(site_id,original_name,stored_name,mime_type,byte_size,alt_text,created_by) VALUES(?,?,?,?,?,?,?)')->execute([$siteId,mb_substr(basename($file['name']),0,255),$stored,$mime,(int)$file['size'],mb_substr(trim((string)post('alt_text')),0,500),user()['id']]);audit('upload','site_asset',(int)db()->lastInsertId(),['mime'=>$mime,'bytes'=>(int)$file['size']]);header('Content-Type:application/json');echo json_encode(['data'=>['src'=>'/site-assets/'.$stored]]);exit;
 }
 $siteId=(int)($_GET['site_id']??0);$q=db()->prepare('SELECT id,original_name,stored_name,mime_type,byte_size,alt_text,created_at FROM site_assets WHERE site_id IS NULL OR site_id=? ORDER BY created_at DESC LIMIT 500');$q->execute([$siteId]);header('Content-Type:application/json');echo json_encode(array_map(fn($a)=>['id'=>$a['id'],'name'=>$a['original_name'],'src'=>'/site-assets/'.$a['stored_name'],'type'=>str_starts_with($a['mime_type'],'image/')?'image':'file','alt'=>$a['alt_text']],$q->fetchAll()));exit;
}
if(preg_match('#^/site-assets/([a-f0-9]{40}\.(?:jpg|png|gif|webp|pdf))$#',$path,$m)){$q=db()->prepare('SELECT mime_type,stored_name FROM site_assets WHERE stored_name=?');$q->execute([$m[1]]);$a=$q->fetch();$file=dirname(__DIR__).'/storage/uploads/site-assets/'.$m[1];if(!$a||!is_file($file)){http_response_code(404);exit;}header('Content-Type: '.$a['mime_type']);header('X-Content-Type-Options: nosniff');header('Cache-Control: public,max-age=31536000,immutable');readfile($file);exit;}

if(preg_match('#^/sites/pages/(\d+)/seo$#',$path,$m)){
 require_permission('sites.edit');$p=enhanced_site_page((int)$m[1]);if($method==='GET'){header('Content-Type:application/json');echo json_encode(array_intersect_key($p,array_flip(['canonical_url','social_title','social_description','social_image_url','noindex'])));exit;}if($method!=='POST'){http_response_code(405);exit;}verify_csrf();$canonical=trim((string)post('canonical_url'));$image=trim((string)post('social_image_url'));if($canonical!==''&&!filter_var($canonical,FILTER_VALIDATE_URL)){http_response_code(422);exit('Invalid canonical URL.');}if($image!==''&&!filter_var($image,FILTER_VALIDATE_URL)&&!str_starts_with($image,'/site-assets/')){http_response_code(422);exit('Invalid social image URL.');}db()->prepare('UPDATE site_pages SET canonical_url=?,social_title=?,social_description=?,social_image_url=?,noindex=?,updated_by=? WHERE id=?')->execute([$canonical?:null,trim((string)post('social_title'))?:null,trim((string)post('social_description'))?:null,$image?:null,post('noindex')?1:0,user()['id'],$p['id']]);audit('update','site_page_seo',(int)$p['id']);header('Content-Type:application/json');echo '{"ok":true}';exit;
}
if(preg_match('#^/sites/pages/(\d+)/versions$#',$path,$m)){
 require_permission('sites.edit');$p=enhanced_site_page((int)$m[1]);if($method==='POST'){verify_csrf();$q=db()->prepare('SELECT * FROM site_page_versions WHERE id=? AND page_id=?');$q->execute([(int)post('version_id'),$p['id']]);$v=$q->fetch();if(!$v){http_response_code(404);exit('Version not found');}$next=db()->prepare('SELECT COALESCE(MAX(version_number),0)+1 FROM site_page_versions WHERE page_id=?');$next->execute([$p['id']]);db()->prepare('INSERT INTO site_page_versions(page_id,version_number,project_json,html,css,custom_js,created_by) VALUES(?,?,?,?,?,?,?)')->execute([$p['id'],(int)$next->fetchColumn(),$p['project_json'],$p['html'],$p['css'],$p['custom_js'],user()['id']]);db()->prepare('UPDATE site_pages SET project_json=?,html=?,css=?,custom_js=?,status=\'draft\',updated_by=? WHERE id=?')->execute([$v['project_json'],$v['html'],$v['css'],$v['custom_js'],user()['id'],$p['id']]);audit('restore','site_page',(int)$p['id'],['version'=>(int)$v['version_number']]);flash('success','Version '.$v['version_number'].' restored as a draft.');redirect('/sites/pages/'.$p['id'].'/edit');}$q=db()->prepare('SELECT v.*,COALESCE(NULLIF(u.display_name,\'\'),u.username) author FROM site_page_versions v LEFT JOIN users u ON u.id=v.created_by WHERE v.page_id=? ORDER BY v.version_number DESC');$q->execute([$p['id']]);$versions=$q->fetchAll();layout('Page history',function()use($p,$versions){?><div class="actions"><h1 style="margin:0"><?=e($p['name'])?> history</h1><span class="spacer"></span><a class="btn secondary" href="/sites/pages/<?=$p['id']?>/edit">Back to editor</a></div><div class="card"><table><thead><tr><th>Version</th><th>Saved</th><th>By</th><th></th></tr></thead><tbody><?php foreach($versions as $v):?><tr><td><?=$v['version_number']?></td><td><?=e($v['created_at'])?></td><td><?=e($v['author']?:'System')?></td><td><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="version_id" value="<?=$v['id']?>"><button class="compact" onclick="return confirm('Restore this version as a draft?')">Restore</button></form></td></tr><?php endforeach?></tbody></table></div><?php });exit;
}

if($path==='/track/site'){
 header('Content-Type:application/json');$input=json_decode((string)file_get_contents('php://input'),true)?:[];$page=enhanced_site_page((int)($input['page_id']??0));if(!site_tracking_allowed($page)){echo '{"consent":false}';exit;}$visitor=preg_match('/^[a-f0-9-]{36}$/',$_COOKIE['oc_vid']??'')?$_COOKIE['oc_vid']:site_uuid();$session=preg_match('/^[a-f0-9-]{36}$/',$_COOKIE['oc_sid']??'')?$_COOKIE['oc_sid']:site_uuid();setcookie('oc_vid',$visitor,['expires'=>time()+31536000,'path'=>'/','secure'=>true,'httponly'=>true,'samesite'=>'Lax']);setcookie('oc_sid',$session,['expires'=>time()+1800,'path'=>'/','secure'=>true,'httponly'=>true,'samesite'=>'Lax']);db()->prepare('INSERT INTO site_visitors(visitor_key,last_seen_at) VALUES(?,NOW()) ON DUPLICATE KEY UPDATE last_seen_at=NOW()')->execute([$visitor]);$v=db()->prepare('SELECT id FROM site_visitors WHERE visitor_key=?');$v->execute([$visitor]);$visitorId=(int)$v->fetchColumn();$s=db()->prepare('SELECT id FROM site_sessions WHERE session_key=?');$s->execute([$session]);$sessionId=(int)$s->fetchColumn();if(!$sessionId){$q=(array)($input['query']??[]);db()->prepare('INSERT INTO site_sessions(visitor_id,site_id,session_key,entry_page_id,exit_page_id,referrer,utm_source,utm_medium,utm_campaign,device_type,ip_hash) VALUES(?,?,?,?,?,?,?,?,?,?,?)')->execute([$visitorId,$page['site_id'],$session,$page['id'],$page['id'],mb_substr((string)($input['referrer']??''),0,2000),mb_substr((string)($q['utm_source']??''),0,190),mb_substr((string)($q['utm_medium']??''),0,190),mb_substr((string)($q['utm_campaign']??''),0,190),promotional_device_type((string)($_SERVER['HTTP_USER_AGENT']??'')),hash_hmac('sha256',(string)($_SERVER['REMOTE_ADDR']??''),(string)config('key'))]);$sessionId=(int)db()->lastInsertId();}else db()->prepare('UPDATE site_sessions SET last_activity_at=NOW(),exit_page_id=? WHERE id=?')->execute([$page['id'],$sessionId]);if(($input['event']??'view')==='engage'){$seconds=max(0,min(3600,(int)($input['seconds']??0)));db()->prepare('UPDATE site_page_views SET engaged_seconds=GREATEST(engaged_seconds,?) WHERE id=? AND session_id=?')->execute([$seconds,(int)($input['view_id']??0),$sessionId]);echo '{"ok":true}';exit;}db()->prepare('INSERT INTO site_page_views(session_id,page_id) VALUES(?,?)')->execute([$sessionId,$page['id']]);echo json_encode(['view_id'=>(int)db()->lastInsertId()]);exit;
}

if(preg_match('#^/s/([a-z0-9_-]+)(?:/([a-z0-9_/-]+))?$#',$path,$m)){
 $slug=trim($m[2]??'','/');$q=db()->prepare("SELECT p.*,s.name site_name,s.tracking_enabled,s.consent_mode FROM site_pages p JOIN sites s ON s.id=p.site_id WHERE s.slug=? AND s.status='published' AND p.status='published' AND (p.slug=? OR (?='' AND p.is_home=1)) LIMIT 1");$q->execute([$m[1],$slug,$slug]);$p=$q->fetch();if(!$p){http_response_code(404);exit('Page not found');}$title=$p['title']?:$p['name'];$socialTitle=$p['social_title']?:$title;$socialDescription=$p['social_description']?:$p['meta_description'];?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=e($title)?></title><meta name="description" content="<?=e($p['meta_description'])?>"><?php if($p['canonical_url']):?><link rel="canonical" href="<?=e($p['canonical_url'])?>"><?php endif?><?php if($p['noindex']):?><meta name="robots" content="noindex,nofollow"><?php endif?><meta property="og:title" content="<?=e($socialTitle)?>"><meta property="og:description" content="<?=e($socialDescription)?>"><?php if($p['social_image_url']):?><meta property="og:image" content="<?=e($p['social_image_url'])?>"><?php endif?><style><?=$p['css']?></style></head><body><?=$p['html']?><?php if($p['tracking_enabled']&&$p['consent_mode']!=='disabled'):?><div id="oc-consent" style="display:none;position:fixed;z-index:2147483647;left:16px;right:16px;bottom:16px;max-width:720px;margin:auto;padding:16px;background:#fff;color:#222;border:1px solid #ddd;border-radius:8px;box-shadow:0 8px 30px #0003"><strong>Privacy</strong><p style="margin:8px 0">We use privacy-conscious analytics to understand visits and improve this site.</p><button data-consent="granted">Allow analytics</button> <button data-consent="denied">Decline</button></div><script>(()=>{const mode=<?=json_encode($p['consent_mode'])?>,box=document.querySelector('#oc-consent');let consent=document.cookie.match(/(?:^|; )oc_consent=([^;]+)/)?.[1]||'';const save=v=>{document.cookie='oc_consent='+v+';path=/;max-age=31536000;secure;samesite=lax';box.style.display='none';if(v==='granted')track()};box.querySelectorAll('button').forEach(b=>b.onclick=()=>save(b.dataset.consent));if(!consent)box.style.display='block';let view=0,start=Date.now(),sent=false;function track(){if(sent||consent==='denied'||(mode==='required'&&consent!=='granted'))return;sent=true;fetch('/track/site',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({page_id:<?=$p['id']?>,event:'view',referrer:document.referrer,query:Object.fromEntries(new URLSearchParams(location.search))})}).then(r=>r.json()).then(x=>view=x.view_id||0)}function engage(){if(!view)return;navigator.sendBeacon('/track/site',new Blob([JSON.stringify({page_id:<?=$p['id']?>,event:'engage',view_id:view,seconds:Math.round((Date.now()-start)/1000)})],{type:'application/json'}))}if(mode==='notice'&&consent!=='denied')track();else if(consent==='granted')track();addEventListener('pagehide',engage);setInterval(engage,15000)})()</script><?php endif?><?php if($p['custom_js']):?><script><?=$p['custom_js']?></script><?php endif?></body></html><?php exit;
}
